mapper.sql:
wq.user_id = #{request.userId}

    and q.type = #{request.type}


    and q.difficulty = #{request.difficulty}


    and q.tags like concat('%', #{request.tag}, '%')


    and q.content like concat('%', #{request.keyword}, '%')


    and wq.paper_id = #{request.paperId}


    and wq.mastered = #{request.mastered}
